package parser

import (
	"encoding/json"
	"fmt"
	"io"
	"os"
)

// JSONParser JSON 文件解析器
type JSONParser struct {
	*BaseParser
}

// NewJSONParser 创建 JSON 解析器
func NewJSONParser() *JSONParser {
	return &JSONParser{
		BaseParser: NewBaseParser("JSON", []string{".json"}),
	}
}

// Parse 从 io.Reader 解析 JSON
func (p *JSONParser) Parse(reader io.Reader) (*ParseResult, error) {
	decoder := json.NewDecoder(reader)

	var raw interface{}
	if err := decoder.Decode(&raw); err != nil {
		return nil, fmt.Errorf("failed to decode JSON: %w", err)
	}

	// 复用 YAML 的树构建逻辑（JSON 和 YAML 的数据结构相同）
	root := buildConfigTree("root", raw)

	return &ParseResult{
		Root: root,
		Raw:  raw,
	}, nil
}

// ParseFile 从文件解析 JSON
func (p *JSONParser) ParseFile(path string) (*ParseResult, error) {
	file, err := os.Open(path)
	if err != nil {
		return nil, fmt.Errorf("failed to open file: %w", err)
	}
	defer file.Close()

	return p.Parse(file)
}

package generate

// Options 定义代码生成的配置选项
type Options struct {
	// InputPath 配置文件路径 (YAML/JSON)
	InputPath string

	// OutputPath 生成的 Go 文件路径
	OutputPath string

	// PackageName 生成代码的包名
	PackageName string

	// WatchMode 是否启用监听模式（文件变化时自动重新生成）
	WatchMode bool

	// DryRun 只打印生成的代码，不写入文件
	DryRun bool

	// StructName 生成的结构体名称，默认为 "Config"
	StructName string

	// Tags 要生成的标签类型，如 ["json", "yaml", "mapstructure"]
	Tags []string
}

// Validate 验证选项的有效性
func (o *Options) Validate() error {
	if o.InputPath == "" {
		return ErrInputPathRequired
	}

	if o.OutputPath == "" && !o.DryRun {
		return ErrOutputPathRequired
	}

	if o.PackageName == "" {
		o.PackageName = "main"
	}

	if o.StructName == "" {
		o.StructName = "Config"
	}

	// 默认生成常用的 tags
	if len(o.Tags) == 0 {
		o.Tags = []string{"json", "yaml", "mapstructure"}
	}

	return nil
}

.PHONY: help build install test clean run example

help:
	@echo "Available commands:"
	@echo "  make build      - Build the confg binary"
	@echo "  make install    - Install confg to GOPATH/bin"
	@echo "  make test       - Run tests"
	@echo "  make clean      - Remove build artifacts"
	@echo "  make run        - Run example generation"
	@echo "  make example    - Generate config from example YAML"

build:
	@echo "Building confg..."
	go build -o bin/confg ./cmd/confg

install:
	@echo "Installing confg..."
	go install ./cmd/confg

test:
	@echo "Running tests..."
	go test -v ./...

clean:
	@echo "Cleaning..."
	rm -rf bin/
	rm -f examples/basic/config_gen.go

run: build
	@echo "Running confg..."
	./bin/confg --help

example: build
	@echo "Generating config from examples/basic/config.yaml..."
	./bin/confg --path=examples/basic/config.yaml --out=examples/basic/config_gen.go --package=main

.DEFAULT_GOAL := help

