func TestParserFactory_ExtensionNormalization(t *testing.T) {
	factory := NewParserFactory()
	yamlParser := NewYAMLParser()
	factory.Register(yamlParser)

	// 测试各种格式的扩展名都能正确匹配
	tests := []string{
		".yaml",
		"yaml",
		".YAML",
		"YAML",
		".Yaml",
