func TestParserFactory_ErrorMessages(t *testing.T) {
	factory := NewParserFactory()
	factory.RegisterDefaultParsers()

	tests := []struct {
		name        string
		path        string
		expectedErr error
	}{
		{
			"unsupported extension",
			"config.toml",
			ErrParserNotFound,
		},
		{
			"no extension",
			"config",
			ErrUnsupportedFormat,
		},
	}

	for _, tt := range tests {
