package tree

// ValueType 配置值的类型
type ValueType int

const (
	TypeString ValueType = iota
	TypeInt
	TypeFloat
	TypeBool
	TypeArray
	TypeObject
	TypeNull
)

// SourceType 配置来源类型
type SourceType int

const (
	SourceFile SourceType = iota   // 配置文件
	SourceEnv                       // 环境变量
	SourceEtcd                      // etcd
	SourceZookeeper                 // Zookeeper
	SourceRemote                    // 其他远程配置中心
	SourceOverride                  // 运行时覆盖
	SourceDefault                   // 默认值
)

// Priority 配置源的优先级（数字越大优先级越高）
var SourcePriority = map[SourceType]int{
	SourceDefault:   0, // 优先级最低
	SourceFile:      10,
	SourceRemote:    20,
	SourceEtcd:      20,
	SourceZookeeper: 20,
	SourceEnv:       30,
	SourceOverride:  100, // 优先级最高
}

// String 返回类型名称
func (t ValueType) String() string {
	names := []string{
		"String", "Int", "Float", "Bool", "Array", "Object", "Null",
	}
	if t >= 0 && int(t) < len(names) {
		return names[t]
	}
	return "Unknown"
}

func (s SourceType) String() string {
	names := []string{
		"File", "Env", "Etcd", "Zookeeper", "Remote", "Override", "Default",
	}
	if s >= 0 && int(s) < len(names) {
		return names[s]
	}
	return "Unknown"
}

package tree

import "fmt"

// SourceValue 表示来自特定源的配置值
type SourceValue struct {
	Value    any        // 实际值
	Source   SourceType // 来源
	Priority int        // 优先级（从 SourcePriority 获取）
}

// ConfigNode 表示配置 Trie 树的节点
// 这是一个多源配置节点，每个节点可以存储来自不同源的多个值
type ConfigNode struct {
	Key  string    // 字段名（Trie 边的标签）
	Type ValueType // 节点类型

	// 多源值存储（按优先级排序，优先级高的在前）
	// 这样可以支持配置覆盖：Env > File > Default
	Values []SourceValue

	// Trie 树的子节点
	Children map[string]*ConfigNode // 对象类型的子节点
	Items    []*ConfigNode          // 数组类型的元素
}

// NewConfigNode 创建新的配置节点
func NewConfigNode(key string) *ConfigNode {
	return &ConfigNode{
		Key:      key,
		Values:   make([]SourceValue, 0, 4), // 预分配 4 个源的空间
		Children: make(map[string]*ConfigNode),
		Items:    make([]*ConfigNode, 0),
	}
}

// SetValue 设置来自特定源的值
// 如果已存在相同源的值，则更新；否则插入并按优先级排序
func (n *ConfigNode) SetValue(value any, source SourceType) {
	priority := SourcePriority[source]
	sourceValue := SourceValue{
		Value:    value,
		Source:   source,
		Priority: priority,
	}

	// 查找是否已存在该源的值
	for i, sv := range n.Values {
		if sv.Source == source {
			// 更新现有值
			n.Values[i] = sourceValue
			return
		}
	}

	// 插入新值并保持优先级排序（降序）
	n.Values = append(n.Values, sourceValue)
	n.sortValues()
}

// GetValue 获取最高优先级的值
func (n *ConfigNode) GetValue() any {
	if len(n.Values) == 0 {
		return nil
	}
	return n.Values[0].Value // 第一个是优先级最高的
}

// GetValueFromSource 获取特定源的值
func (n *ConfigNode) GetValueFromSource(source SourceType) (any, bool) {
	for _, sv := range n.Values {
		if sv.Source == source {
			return sv.Value, true
		}
	}
	return nil, false
}

// GetAllValues 获取所有源的值（按优先级排序）
func (n *ConfigNode) GetAllValues() []SourceValue {
	return n.Values
}

// RemoveSource 移除特定源的值
func (n *ConfigNode) RemoveSource(source SourceType) bool {
	for i, sv := range n.Values {
		if sv.Source == source {
			n.Values = append(n.Values[:i], n.Values[i+1:]...)
			return true
		}
	}
	return false
}

// sortValues 按优先级排序（降序：优先级高的在前）
func (n *ConfigNode) sortValues() {
	// 简单的冒泡排序（因为 Values 通常很小，< 10 个元素）
	for i := 0; i < len(n.Values)-1; i++ {
		for j := i + 1; j < len(n.Values); j++ {
			if n.Values[i].Priority < n.Values[j].Priority {
				n.Values[i], n.Values[j] = n.Values[j], n.Values[i]
			}
		}
	}
}

// AddChild 添加子节点（对象类型）
func (n *ConfigNode) AddChild(child *ConfigNode) {
	if n.Children == nil {
		n.Children = make(map[string]*ConfigNode)
	}
	n.Children[child.Key] = child
}

// AddItem 添加数组元素（数组类型）
func (n *ConfigNode) AddItem(item *ConfigNode) {
	n.Items = append(n.Items, item)
}

// GetChild 获取子节点
func (n *ConfigNode) GetChild(key string) (*ConfigNode, bool) {
	child, ok := n.Children[key]
	return child, ok
}

// IsObject 是否为对象类型
func (n *ConfigNode) IsObject() bool {
	return n.Type == TypeObject
}

// IsArray 是否为数组类型
func (n *ConfigNode) IsArray() bool {
	return n.Type == TypeArray
}

// IsPrimitive 是否为基本类型
func (n *ConfigNode) IsPrimitive() bool {
	return n.Type == TypeString || n.Type == TypeInt ||
		n.Type == TypeFloat || n.Type == TypeBool || n.Type == TypeNull
}

// HasValue 是否有值（来自任何源）
func (n *ConfigNode) HasValue() bool {
	return len(n.Values) > 0
}

// String 返回节点的字符串表示（用于调试）
func (n *ConfigNode) String() string {
	if len(n.Values) == 0 {
		return fmt.Sprintf("%s (%s): <no value>", n.Key, n.Type)
	}
	highestValue := n.Values[0]
	return fmt.Sprintf("%s (%s): %v [from %s]",
		n.Key, n.Type, highestValue.Value, highestValue.Source)
}

package tree

import (
	"fmt"
	"strings"
)

// ConfigTree 配置 Trie 树
// 支持多源配置，每个路径可以有多个来源的值
type ConfigTree struct {
	Root *ConfigNode // 根节点
}

// NewConfigTree 创建新的配置树
func NewConfigTree() *ConfigTree {
	return &ConfigTree{
		Root: NewConfigNode("root"),
	}
}

// Get 根据路径获取节点
// path 格式: "server.host" 或 []string{"server", "host"}
func (t *ConfigTree) Get(path string) *ConfigNode {
	return t.GetByPath(strings.Split(path, "."))
}

// GetByPath 根据路径数组获取节点
func (t *ConfigTree) GetByPath(path []string) *ConfigNode {
	node := t.Root
	for _, key := range path {
		if key == "" {
			continue
		}

		child, ok := node.GetChild(key)
		if !ok {
			return nil
		}
		node = child
	}
	return node
}

// GetValue 获取路径的值（最高优先级）
func (t *ConfigTree) GetValue(path string) (any, bool) {
	node := t.Get(path)
	if node == nil || !node.HasValue() {
		return nil, false
	}
	return node.GetValue(), true
}

// Set 设置值到指定路径和源
// 如果路径不存在，会自动创建中间节点
func (t *ConfigTree) Set(path string, value any, source SourceType, valueType ValueType) error {
	return t.SetByPath(strings.Split(path, "."), value, source, valueType)
}

// SetByPath 使用路径数组设置值
func (t *ConfigTree) SetByPath(path []string, value any, source SourceType, valueType ValueType) error {
	if len(path) == 0 {
		return fmt.Errorf("path cannot be empty")
	}

	// 遍历路径，创建不存在的节点
	node := t.Root
	for i, key := range path {
		if key == "" {
			continue
		}

		child, ok := node.GetChild(key)
		if !ok {
			// 创建新节点
			child = NewConfigNode(key)

			// 如果是最后一个键，设置为实际类型；否则设置为对象
			if i == len(path)-1 {
				child.Type = valueType
			} else {
				child.Type = TypeObject
			}

			node.AddChild(child)
		}
		node = child
	}

	// 设置值
	node.SetValue(value, source)
	return nil
}

// Merge 合并另一棵树到当前树
// 用于合并来自不同源的配置
func (t *ConfigTree) Merge(other *ConfigTree, source SourceType) {
	t.mergeNode(t.Root, other.Root, source)
}

// mergeNode 递归合并节点
func (t *ConfigTree) mergeNode(target, source *ConfigNode, sourceType SourceType) {
	// 合并值
	if source.HasValue() {
		target.SetValue(source.GetValue(), sourceType)
		target.Type = source.Type
	}

	// 递归合并子节点
	for key, sourceChild := range source.Children {
		targetChild, ok := target.GetChild(key)
		if !ok {
			// 目标节点不存在，直接复制
			targetChild = copyNode(sourceChild, sourceType)
			target.AddChild(targetChild)
		} else {
			// 递归合并
			t.mergeNode(targetChild, sourceChild, sourceType)
		}
	}

	// 合并数组元素
	if source.IsArray() {
		// 简单策略：用新的数组覆盖旧的
		target.Items = make([]*ConfigNode, len(source.Items))
		for i, item := range source.Items {
			target.Items[i] = copyNode(item, sourceType)
		}
	}
}

// copyNode 复制节点（深拷贝）
func copyNode(source *ConfigNode, sourceType SourceType) *ConfigNode {
	node := NewConfigNode(source.Key)
	node.Type = source.Type

	// 复制值
	if source.HasValue() {
		node.SetValue(source.GetValue(), sourceType)
	}

	// 递归复制子节点
	for _, child := range source.Children {
		node.AddChild(copyNode(child, sourceType))
	}

	// 复制数组元素
	for _, item := range source.Items {
		node.AddItem(copyNode(item, sourceType))
	}

	return node
}

// GetAllWithPrefix 获取所有具有指定前缀的节点
// 这是 Trie 树的特色功能
func (t *ConfigTree) GetAllWithPrefix(prefix string) map[string]*ConfigNode {
	node := t.Get(prefix)
	if node == nil {
		return nil
	}

	result := make(map[string]*ConfigNode)
	for key, child := range node.Children {
		fullPath := prefix + "." + key
		result[fullPath] = child
	}
	return result
}

// Walk 遍历整棵树
func (t *ConfigTree) Walk(fn func(path string, node *ConfigNode)) {
	t.walkNode(t.Root, "", fn)
}

// walkNode 递归遍历节点
func (t *ConfigTree) walkNode(node *ConfigNode, path string, fn func(string, *ConfigNode)) {
	if path != "" { // 跳过根节点
		fn(path, node)
	}

	// 遍历子节点
	for key, child := range node.Children {
		childPath := path
		if childPath != "" {
			childPath += "."
		}
		childPath += key
		t.walkNode(child, childPath, fn)
	}
}

// ToMap 将树转换为嵌套 map（用于序列化）
// 只返回最高优先级的值
func (t *ConfigTree) ToMap() map[string]any {
	return t.nodeToMap(t.Root)
}

// nodeToMap 递归转换节点为 map
func (t *ConfigTree) nodeToMap(node *ConfigNode) map[string]any {
	if node.IsPrimitive() {
		return nil // 基本类型直接返回值
	}

	result := make(map[string]any)

	if node.IsObject() {
		for key, child := range node.Children {
			if child.IsPrimitive() {
				result[key] = child.GetValue()
			} else if child.IsObject() {
				result[key] = t.nodeToMap(child)
			} else if child.IsArray() {
				result[key] = t.nodeToArray(child)
			}
		}
	}

	return result
}

// nodeToArray 转换数组节点
func (t *ConfigTree) nodeToArray(node *ConfigNode) []any {
	result := make([]any, len(node.Items))
	for i, item := range node.Items {
		if item.IsPrimitive() {
			result[i] = item.GetValue()
		} else if item.IsObject() {
			result[i] = t.nodeToMap(item)
		} else if item.IsArray() {
			result[i] = t.nodeToArray(item)
		}
	}
	return result
}

// Print 打印树结构（用于调试）
func (t *ConfigTree) Print() {
	t.printNode(t.Root, "", true)
}

// printNode 递归打印节点
func (t *ConfigTree) printNode(node *ConfigNode, prefix string, isLast bool) {
	if node.Key != "root" {
		marker := "├─"
		if isLast {
			marker = "└─"
		}
		fmt.Printf("%s%s %s\n", prefix, marker, node.String())

		if isLast {
			prefix += "  "
		} else {
			prefix += "│ "
		}
	}

	// 打印子节点
	children := make([]*ConfigNode, 0, len(node.Children))
	for _, child := range node.Children {
		children = append(children, child)
	}

	for i, child := range children {
		t.printNode(child, prefix, i == len(children)-1)
	}
}

