// findInsertPosition finds the correct position to insert a new value
// using binary search to maintain descending order by priority
func (n *ConfigNode) findInsertPosition(priority int) int {
	// Binary search for insertion position
	// Values are sorted in descending order (highest priority first)
	left, right := 0, len(n.Values)

	for left < right {
		mid := left + (right-left)/2
		if n.Values[mid].Priority > priority {
			// Priority at mid is higher, search right half
			left = mid + 1
		} else {
			// Priority at mid is lower or equal, search left half
			right = mid
		}
	}

	return left
}

