package tree

import (
	"testing"
)

// Benchmark linear search (current implementation)
func BenchmarkGetValueFromSource_Linear(b *testing.B) {
	node := NewConfigNode("test")

	// Set up 7 sources (typical max)
	sources := []SourceType{
		SourceDefault, SourceRemote, SourceFile,
		SourceRuntimeOverride, SourceSessionEnv,
		SourceSystemEnv, SourceCodeOverride,
	}

	for i, src := range sources {
		node.SetValue(i, src)
	}

	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		// Worst case: search for last element
		node.GetValueFromSource(SourceDefault)
	}
}

// Benchmark map-based lookup (alternative)
func BenchmarkGetValueFromSource_Map(b *testing.B) {
	// Simulate map-based approach
	sourceMap := make(map[SourceType]any)

	sources := []SourceType{
		SourceDefault, SourceRemote, SourceFile,
		SourceRuntimeOverride, SourceSessionEnv,
		SourceSystemEnv, SourceCodeOverride,
	}

	for i, src := range sources {
		sourceMap[src] = i
	}

	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		_ = sourceMap[SourceDefault]
	}
}

// Benchmark GetValue (most common operation)
func BenchmarkGetValue(b *testing.B) {
	node := NewConfigNode("test")
	node.SetValue("localhost", SourceFile)
	node.SetValue("prod.com", SourceSystemEnv)
	node.SetValue("override.com", SourceCodeOverride)

	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		_ = node.GetValue() // O(1) - just get first element
	}
}

// Benchmark SetValue (insert with binary search)
func BenchmarkSetValue(b *testing.B) {
	sources := []SourceType{
		SourceFile, SourceSystemEnv, SourceRemote,
	}

	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		node := NewConfigNode("test")
		for _, src := range sources {
			node.SetValue("value", src)
		}
	}
}
